from fastapi import FastAPI, Response
from contextlib import asynccontextmanager
import psutil
import time
import asyncio

app = FastAPI()

# Shared state (in production, use proper state management)
AGENT_STATE = {
    'started_at': time.time(),
    'rate_limit_remaining': 1000,
    'active_tasks': 0,
    'db_healthy': True,
}

@app.get('/health/live')
async def liveness():
    """Liveness: is the process alive and not deadlocked?"""
    return {'status': 'alive', 'uptime_seconds': int(time.time() - AGENT_STATE['started_at'])}

@app.get('/health/ready')
async def readiness(response: Response):
    """Readiness: can this instance accept new work right now?"""
    checks = {}
    healthy = True

    # Check 1: Rate limit budget
    rate_ok = AGENT_STATE['rate_limit_remaining'] > 50
    checks['rate_limit'] = {'ok': rate_ok, 'remaining': AGENT_STATE['rate_limit_remaining']}
    if not rate_ok:
        healthy = False

    # Check 2: Memory headroom
    mem = psutil.virtual_memory()
    mem_ok = mem.percent < 85
    checks['memory'] = {'ok': mem_ok, 'used_percent': round(mem.percent, 1)}
    if not mem_ok:
        healthy = False

    # Check 3: Database connectivity (fast path — no external call, just check cached flag)
    checks['database'] = {'ok': AGENT_STATE['db_healthy']}
    if not AGENT_STATE['db_healthy']:
        healthy = False

    # Check 4: Task capacity
    tasks_ok = AGENT_STATE['active_tasks'] < 10
    checks['task_capacity'] = {'ok': tasks_ok, 'active': AGENT_STATE['active_tasks']}
    if not tasks_ok:
        healthy = False

    status_code = 200 if healthy else 503
    response.status_code = status_code
    return {
        'status': 'ready' if healthy else 'not_ready',
        'checks': checks,
        'timestamp': time.time(),
    }

@app.get('/health/startup')
async def startup_check():
    """Startup probe: have we finished initializing?"""
    startup_seconds = time.time() - AGENT_STATE['started_at']
    initialized = startup_seconds > 5  # allow 5s for init
    return {'initialized': initialized, 'startup_seconds': startup_seconds}
